class Solution:
    def findTarget(self, root, k):
        vals = []
        def walk(n):
            if not n:
                return
            vals.append(n.val)
            walk(n.left)
            walk(n.right)
        walk(root)
        for i in range(len(vals)):
            for j in range(i + 1, len(vals)):
                if vals[i] + vals[j] == k:
                    return True
        return False

