class Solution:
    def findTarget(self, root, k):
        seen = set()
        stack = [root] if root else []
        while stack:
            n = stack.pop()
            if k - n.val in seen:
                return True
            seen.add(n.val)
            if n.left:
                stack.append(n.left)
            if n.right:
                stack.append(n.right)
        return False

