var findTarget = function(root, k) {
    const seen = new Set();
    const stack = root ? [root] : [];
    while (stack.length) {
        const n = stack.pop();
        if (seen.has(k - n.val)) return true;
        seen.add(n.val);
        if (n.left) stack.push(n.left);
        if (n.right) stack.push(n.right);
    }
    return false;
};
